import{_ as t,o,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/2492_華新科/20260512/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/2492_華新科/20260512/F02_營業現金流與獲利品質.md"}'),i={name:"審計報告庫/財務審計/2492_華新科/20260512/F02_營業現金流與獲利品質.md"};function n(e,a,s,h,g,d){return o(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="f02-營業現金流與獲利品質-財務審計專家-審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務審計專家 審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務審計專家-審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營業活動現金流量(CFO)與稅後淨利之關係為何？獲利是否具備實質現金支撐？判定盈餘含金量與獲利真實性。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI比值500%+，FCF由2025年3.4億跳升至Q1 8.9億。折舊40-50億壓低帳面淨利，屬重資產結構。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2026年Q1</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>CFO/NI比值</strong>：2023年-7,246%（NI為負但CFO仍正流入85億）、2024年514%、2025年543%。三年均值極高，反映製造業重資產特性。</li><li><strong>CFO趨勢</strong>：2023年84.9億→2024年61.4億→2025年61.5億，2024年下降後持平。Q1 2026為11.2億（年化約44.7億）。</li><li><strong>FCF走勢</strong>：2023年-97.9億→2024年-8.2億→2025年+3.4億。2025年為轉折年，Q1 2026已達+8.9億，改善趨勢明確。</li><li><strong>診斷見解</strong>：帳面淨利僅約11-12億，但CFO為60億+，差額主要來自折舊（年約40-50億）。此非盈餘膨風，而是重資產製造業的正常結構，但表示公司「真實賺錢能力」遠高於損益表呈現。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-cfo-ni-拆解與非現金項目" tabindex="-1">1. CFO/NI 拆解與非現金項目 <a class="header-anchor" href="#_1-cfo-ni-拆解與非現金項目" aria-label="Permalink to &quot;1. CFO/NI 拆解與非現金項目&quot;">​</a></h3><ul><li><strong>折舊掩蓋診斷</strong>：年折舊費用2023年49.6億、2024年48.6億、2025年40.8億（逐年下降），為CFO與淨利最大背離來源。排除折舊後，營運產生現金流（Cash Received Through Operations）分別為83.6億、67.3億、53.1億。</li><li><strong>收益費損合計</strong>：2023年39.3億→2024年27.6億→2025年25.6億，逐年遞減，主因折舊到期資產增加（部分設備已折舊完畢）。</li><li><strong>2023年異常分析</strong>：NI為-1.2億（稅前淨利仍有34.8億），主因大幅業外損失或所得稅費用所致。但CFO達84.9億，顯示核心營運完全正常。</li></ul><h3 id="_2-營運資金管理效率" tabindex="-1">2. 營運資金管理效率 <a class="header-anchor" href="#_2-營運資金管理效率" aria-label="Permalink to &quot;2. 營運資金管理效率&quot;">​</a></h3><ul><li><strong>應收帳款變動</strong>：2023年-2.5億→2024年-8.3億→2025年-4.0億（負值=回收優於新增=現金流入），屬於正向管理。</li><li><strong>存貨變動</strong>：2023年+8.1億（存貨增加=現金流出）→2024年-11.7億（去化=現金流入）→2025年-7.7億（持續去化）。2024-2025年存貨持續下降，顯示庫存管理改善。</li><li><strong>應付帳款變動</strong>：三年分別+8.9億、+6.5億、+8.2億，穩定向上，反映對供應商議價能力。</li><li><strong>營運資金總結</strong>：2024-2025年存貨+應收同步下降而應付上升，營運資金持續產生現金流入，結構健康。</li></ul><h3 id="_3-fcf穿透與投資效率" tabindex="-1">3. FCF穿透與投資效率 <a class="header-anchor" href="#_3-fcf穿透與投資效率" aria-label="Permalink to &quot;3. FCF穿透與投資效率&quot;">​</a></h3><ul><li><strong>CapEx逐年下降</strong>：2023年23.2億、2024年12.4億、2025年10.3億。投資高峰已過（2023年投資活動淨流出182.8億，主因為長期投資/廠房擴建）。</li><li><strong>FCF轉正意義</strong>：從-97.9億（2023）→-8.2億（2024）→+3.4億（2025），為重要轉折。Q1 2026 FCF達8.9億（CFO 11.2億－CapEx 2.3億），年化約35.5億，為近年最佳水準。</li><li><strong>現金餘額</strong>：期末現金從66.2億(2023)→79.4億(2024)→81.6億(2025)→95.6億(Q1 2026)，現金水準持續增加。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>淨利隱含波動風險</strong>：帳面淨利僅11-12億，CFO/NI比值極高不代表獲利強勁，而是折舊吃掉大半獲利。若設備需更新（CapEx回升），FCF將再度承壓。</li><li><strong>2023年鉅額投資後遺症</strong>：2023年投資活動淨流出182.8億（可能是廠房/設備擴建或併購），導致當年FCF為-97.9億。此類資本密集投資的回報周期長，若產能利用率未達預期，恐拖累未來現金流。</li><li><strong>獲利波動風險</strong>：2023年NI為負值（-1.2億），反映被動元件產業景氣循環對獲利的顯著影響。2026年漲價利多消退後，獲利可能再度受壓。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>真實提款能力強</strong>：CFO穩定在60億+水準，期末現金持續增至95.6億，即使2023年產業低谷CFO仍達85億。公司具備在景氣下行時維持營運的現金緩衝。</li><li><strong>存貨去化趨勢明確</strong>：存貨從2023年增加8.1億轉為2024-2025年分別減少11.7億和7.7億，顯示存貨管理效率明顯提升，減少資金佔用。</li><li><strong>FCF改善動能強勁</strong>：從2023年-FCF 97.9億到Q1 2026單季+FCF 8.9億，三年內扭轉。若維持此動能，2026全年FCF有機會挑戰35-40億，股利發放具備提升空間。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科為典型的「重資產賺現金」模式：帳面淨利被折舊壓低，但真實現金產出能力強勁。CFO穩定、存貨去化中、現金持續累積。主要風險在於景氣循環可能導致淨利進一步萎縮，以及未來CapEx回升對FCF的壓縮。整體獲利品質屬中上水準。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (cashflow_quality 2492 2023 2025)</li><li><strong>原始數據</strong>：FinMind TaiwanStockCashFlowsStatement</li><li><strong>查詢參數</strong>：stock_id=2492, cash_flow range=2023-01-01~2026-05-12</li><li><strong>關鍵核對碼</strong>：2025年Depreciation=4,083,512,000；CapEx(P&amp;E)=1,032,006,000；期末現金=8,160,463,000</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const _=t(i,[["render",n]]);export{F as __pageData,_ as default};
